SELECT 
FROM t_finance_disclosure_snapshot
WHERE tenant_id = #{tenantId}
  AND disclosure_type = #{disclosureType}
  AND period = #{period}
ORDER BY statistics_version DESC
LIMIT 1

SELECT 
FROM t_finance_disclosure_snapshot
WHERE tenant_id = #{tenantId}
  AND disclosure_type = #{disclosureType}
  AND status = #{publishedStatus}
ORDER BY published_at DESC, snapshot_id DESC
LIMIT 1
